declare @cookie varchar(32), @ma_khoa varchar(32)
select @ma_khoa = ma_khoa, @cookie = convert(varchar(19), datetime2, 121) from @@prime$partition$current where stt_rec = @stt_rec
select @cookie as cookie, rtrim(a.ma_mh) as ma_mh, a.ten_khoa%l, b.ten_mh%l, a.ma_dvdt, c.ten_dvdt%l, a.loai_hinh_dt, d.ten_loai%l, a.ngay_hoc1, a.ngay_hoc2
    , @ma_khoa as t_khoa, a.stt_rec as stt_rec_kh, a.ngay_ct as ngay_ct_kh
  from hrdtkh a with(nolock) left join hrdmmh b with(nolock) on a.ma_mh = b.ma_mh
    left join hrdmdvdt c with(nolock) on a.ma_dvdt = c.ma_dvdt
    left join hrdmlhdt d with(nolock) on a.loai_hinh_dt = d.ma_loai
  where ma_khoa = @ma_khoa
return




