var f = this, id = f.get_id(), g = f.getItem("d09")._controlBehavior, v = f._language == 'v';
var l2 = g._getColumnOrder('ma_nv');
var e = (v ? 'Có tồn tại mã nhân viên trùng nhau trong phần thông tin chi tiết, không thể lưu được.' : 'Invalid employee id, it already exists.');
var a = query$Select(g, 'count$1 $groupBy ma_nv');
for (var i = 0; i < a.length; i++) {
  if (a[i][1] > 1) {
    f._checked = false;
    $func.hideWait(id);
    for (var j = 1; j <= g._rowCount; j++) {
      g._errorMultiEmployee = g._getItem(j, l2);
      if(a[i][0] == g._getItemValue(j, l2)){
        $message.show(e, String.format('$find(\'{0}\').focus(\'d09\');$find(\'{1}\')._errorMultiEmployee.focus()', id, g.get_id()));
        break;
      }
    }
    break;
  }
}
