script.text:
      &ScriptQueryData;

function active$Voucher$(f) {
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._action == 'New') f.setItemValue('ngay_ct', new Date());
  if (f._action != 'View') f.setReadOnlyFields('ma_mh,ma_dvdt,ngay_hoc1,ngay_hoc2,loai_hinh_dt');
  &ListCreate;
  &PostCreate;
}
/* <flatten type="Javascript"> */
function scatter$Voucher$(f) {
  if (f._action == 'New') {f.setItemValue('ngay_ct', new Date());}
  if (f._action != 'View') f.setReadOnlyFields('ma_mh,ma_dvdt,ngay_hoc1,ngay_hoc2,loai_hinh_dt');
  if (f._action == 'View') {
    var o = f.getItem('ma_khoa');
    if (o._controlBehavior && o.field) {
      var field = o.field;
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($df.completionFilter(f._fields, field.ItemKeyFilter, f._id, f._form));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($df.completionFilter(f._fields, field.ItemCheckFilter, f._id, f._form));
    }
  }
}
/* </flatten> */
function close$Voucher$(f) {
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  objectBehavior$Voucher$Number.dispose(f);
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d09')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d09'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}

      &ScriptVoucherNumber;

function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Course':
      f.setItemValue('stt_rec_kh', result[8].Value);
      f.setItemControlBehavior('ma_mh', result[0].Value, result[1].Value, false);
      f.setItemControlBehavior('ma_dvdt', result[2].Value, result[3].Value, false);
      f.setItemControlBehavior('loai_hinh_dt', result[4].Value, result[5].Value, false);
      f.setItemValue('ngay_hoc1', result[6].Value);
      f.setItemValue('ngay_hoc2', result[7].Value);
      f.setItemValue('ngay_ct_kh', result[9].Value);
      break;
    case 'Scattering':
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
